agent-browser eval "const table = document.querySelector('.bc-table table'); if (!table) return 'Table not found'; const headers = Array.from(table.querySelectorAll('thead th')).map(th => th.textContent.trim()); const chromeIdx = headers.indexOf('Chrome'); const firefoxIdx = headers.indexOf('Firefox'); const safariIdx = headers.indexOf('Safari'); if (chromeIdx === -1 || firefoxIdx === -1 || safariIdx === -1) return 'Headers not found'; const rows = Array.from(table.querySelectorAll('tbody tr')); let resizeObserverRow; for (let row of rows) { const cells = row.querySelectorAll('td'); if (cells.length > 0 && cells[0].textContent.trim() === 'ResizeObserver') { resizeObserverRow = row; break; } } if (!resizeObserverRow) return 'ResizeObserver row not found'; const getVersion = (cell) => { const text = cell.textContent.trim(); const match = text.match(/^(\d+)/); return match ? match[1] : 'No'; }; const chromeVersion = getVersion(resizeObserverRow.cells[chromeIdx]); const firefoxVersion = getVersion(resizeObserverRow.cells[firefoxIdx]); const safariVersion = getVersion(resizeObserverRow.cells[safariIdx]); let borderBoxRow; for (let row of rows) { const cells = row.querySelectorAll('td'); if (cells.length > 0 && cells[0].textContent.trim().includes('borderBoxSize')) { borderBoxRow = row; break; } } if (!borderBoxRow) return 'borderBoxSize row not found'; const safariBorderBoxCell = borderBoxRow.cells[safariIdx]; const text = safariBorderBoxCell.textContent.trim(); let status = 'No'; if (text.match(/^\d+/)) { status = 'Yes'; } else if (text.includes('flag')) { status = 'Partial'; } return \`ChromeMinVersion: \${chromeVersion}
FirefoxMinVersion: \${firefoxVersion}
SafariMinVersion: \${safariVersion}
SafariBorderBoxSize: \${status}\`;"

